import { useState, useEffect } from 'react';
import './App.css';

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL;

function App() {
  const [products, setProducts] = useState([]);
  const [bestSellers, setBestSellers] = useState([]);
  const [cart, setCart] = useState([]);
  const [authToken, setAuthToken] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showCart, setShowCart] = useState(false);

  const [newProduct, setNewProduct] = useState({
    name: '',
    price: '',
    file: null
  });

  const [uploading, setUploading] = useState(false);

  // ================= JWT Decode =================
  const decodeJWT = (token) => {
    try {
      const base64Url = token.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(
        window.atob(base64)
          .split('')
          .map(c => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
          .join('')
      );
      return JSON.parse(jsonPayload);
    } catch {
      return null;
    }
  };

  // ================= Load Session =================
  const checkActiveSession = () => {
    const savedToken = localStorage.getItem('cognito_jwt_token');

    if (!savedToken) return;

    setAuthToken(savedToken);

    const decoded = decodeJWT(savedToken);
    if (decoded) {
      const groups = decoded["cognito:groups"] || [];
      setIsAdmin(groups.includes("Admins"));
    }
  };

  // ================= REAL LOGIN (replace later with Cognito Hosted UI) =================
  const handleLoginSimulation = (role) => {
    // ⚠️ ده TEMP فقط للتجربة
    const payload =
      role === 'admin'
        ? { "cognito:groups": ["Admins"], username: "admin_user" }
        : { username: "user" };

    const token = `header.${window.btoa(JSON.stringify(payload))}.sig`;

    localStorage.setItem('cognito_jwt_token', token);
    setAuthToken(token);
    checkActiveSession();
  };

  const handleLogout = () => {
    localStorage.removeItem('cognito_jwt_token');
    setAuthToken(null);
    setIsAdmin(false);
  };

  // ================= PRODUCTS =================
  const fetchProducts = async () => {
    try {
      const res = await fetch(`${API_BASE_URL}/products`);
      const data = await res.json();
      setProducts(data.data || []);
    } catch (err) {
      console.log("ERROR:", err);
    }
  };

  // ================= BEST SELLERS =================
  useEffect(() => {
    fetch(`${API_BASE_URL}/best-sellers`)
      .then(res => res.json())
      .then(data => setBestSellers(data.data || []))
      .catch(() => console.log("Best sellers not loaded"));
  }, []);

  // ================= INIT =================
  useEffect(() => {
    fetchProducts();
    checkActiveSession();
  }, []);

  // ================= ADD PRODUCT =================
  const handleAddProduct = async (e) => {
    e.preventDefault();
    setUploading(true);

    try {
      const urlResponse = await fetch(
        `${API_BASE_URL}/admin/products/upload-url`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${authToken}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            file_name: newProduct.file.name
          })
        }
      );

      const { upload_url, file_url } = await urlResponse.json();

      await fetch(upload_url, {
        method: 'PUT',
        body: newProduct.file
      });

      await fetch(`${API_BASE_URL}/admin/products`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${authToken}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: newProduct.name,
          price: Number(newProduct.price),
          image_url: file_url
        })
      });

      alert("Product added!");
      fetchProducts();

    } catch (err) {
      console.log(err);
      alert("Failed");
    } finally {
      setUploading(false);
    }
  };

  // ================= CHECKOUT =================
  const handleCheckout = async () => {
    try {
      const res = await fetch(`${API_BASE_URL}/checkout`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${authToken}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          items: cart,
          total: cart.reduce((s, i) => s + i.price, 0)
        })
      });

      if (res.ok) {
        alert("Order placed!");
        setCart([]);
        setShowCart(false);
      }
    } catch {
      alert("Checkout failed");
    }
  };

  // ================= UI =================
  return (
    <div style={{ fontFamily: 'Arial', padding: 20 }}>

      {/* HEADER */}
      <div style={{ display: 'flex', justifyContent: 'space-between', background: '#111', color: '#fff', padding: 10 }}>
        <h2>Cloud Store</h2>

        <div>
          {!authToken ? (
            <>
              <button onClick={() => handleLoginSimulation('user')}>User</button>
              <button onClick={() => handleLoginSimulation('admin')}>Admin</button>
            </>
          ) : (
            <button onClick={handleLogout}>Logout</button>
          )}

          <button onClick={() => setShowCart(!showCart)}>
            Cart ({cart.length})
          </button>
        </div>
      </div>

      {/* CART */}
      {showCart && (
        <div>
          <h3>Cart</h3>
          {cart.map((i, idx) => (
            <p key={idx}>{i.name} - ${i.price}</p>
          ))}
          <button onClick={handleCheckout}>Checkout</button>
        </div>
      )}

      {/* ADMIN */}
      {isAdmin && (
        <div>
          <h3>Admin Panel</h3>

          <form onSubmit={handleAddProduct}>
            <input
              placeholder="Name"
              onChange={e => setNewProduct({ ...newProduct, name: e.target.value })}
              required
            />

            <input
              type="number"
              placeholder="Price"
              onChange={e => setNewProduct({ ...newProduct, price: e.target.value })}
              required
            />

            <input
              type="file"
              onChange={e => setNewProduct({ ...newProduct, file: e.target.files[0] })}
              required
            />

            <button type="submit" disabled={uploading}>
              Add Product
            </button>
          </form>
        </div>
      )}

      {/* PRODUCTS */}
      <h3>Products</h3>
      <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
        {products.map(p => (
          <div key={p.id} style={{ border: '1px solid #ddd', padding: 10 }}>
            <img src={p.image_url} width="100" />
            <h4>{p.name}</h4>
            <p>${p.price}</p>
            <button onClick={() => setCart([...cart, p])}>Add</button>
          </div>
        ))}
      </div>

      {/* BEST SELLERS */}
      <h3>Best Sellers</h3>
      {bestSellers.map(p => (
        <div key={p.id}>{p.name}</div>
      ))}
    </div>
  );
}

export default App;
